Patch Set 4:

If the import is at DISCON state, it won't call l_wait_event

int ptlrpc_disconnect_import(struct obd_import *imp, int noclose)
{
        ...       
        if (ptlrpc_import_in_recovery(imp)) {
                ...
                rc = l_wait_event(imp->imp_recovery_waitq,
                                  !ptlrpc_import_in_recovery(imp), &lwi);

        }
        ...
}

int ptlrpc_import_in_recovery(struct obd_import *imp)
{       
        int in_recovery = 1;

        spin_lock(&imp->imp_lock); 
        if (imp->imp_state == LUSTRE_IMP_FULL ||
            imp->imp_state == LUSTRE_IMP_CLOSED ||
            imp->imp_state == LUSTRE_IMP_DISCON ||
            imp->imp_obd->obd_no_recov)
                in_recovery = 0;
        spin_unlock(&imp->imp_lock);

        return in_recovery;                 
}

Patch Set 5:

changing the "back_to_sleep" to "NULL" in "ptlrpc_disconnect_import" will affect the normal case
which the import is really in recovery and needed to wait for its completion.

it's better to fix by changing the "ptlrpc_import_in_recovery" to add other states (NEW and other states?)

int ptlrpc_import_in_recovery(struct obd_import *imp)
{       
        int in_recovery = 1;
        spin_lock(&imp->imp_lock); 
        if (imp->imp_state == LUSTRE_IMP_FULL ||
            imp->imp_state == LUSTRE_IMP_NEW ||       <----here
            imp->imp_state == LUSTRE_IMP_CLOSED ||
            imp->imp_state == LUSTRE_IMP_DISCON ||
            imp->imp_obd->obd_no_recov)
                in_recovery = 0;
        spin_unlock(&imp->imp_lock);

        return in_recovery;                 
}
